const updateImportMaps=(e,t)=>{for(const o of e.refs)t.refs.add(o);for(const[o,s]of e.import)addValues(t.import,o,s);for(const[o,s]of e.importAs)addNsValues(t.importAs,o,s);for(const[o,s]of e.importNs)addValues(t.importNs,o,s);for(const[o,s]of e.reExport)addValues(t.reExport,o,s);for(const[o,s]of e.reExportAs)addNsValues(t.reExportAs,o,s);for(const[o,s]of e.reExportNs)addValues(t.reExportNs,o,s)};export const updateImportMap=(e,t,o)=>{for(const[s,r]of t){const t=e.imports.internal.get(s);t?updateImportMaps(r,t):e.imports.internal.set(s,r);const a=o.get(s)??createFileNode();a.importedBy||(a.importedBy=createImports()),updateImportMaps(r,a.importedBy),o.set(s,a)}};export const createFileNode=()=>({imports:{internal:new Map,external:new Set,externalRefs:new Set,unresolved:new Set,programFiles:new Set,entryFiles:new Set,imports:new Set},exports:new Map,duplicates:new Set,scripts:new Set,importedBy:void 0,internalImportCache:void 0});export const createImports=()=>({refs:new Set,import:new Map,importAs:new Map,importNs:new Map,reExport:new Map,reExportAs:new Map,reExportNs:new Map});export const addValue=(e,t,o)=>{e.has(t)?e.get(t)?.add(o):e.set(t,new Set([o]))};export const addNsValue=(e,t,o,s)=>{e.has(t)?e.get(t)?.has(o)?e.get(t)?.get(o)?.add(s):e.get(t)?.set(o,new Set([s])):e.set(t,new Map([[o,new Set([s])]]))};const addValues=(e,t,o)=>{if(e.has(t))for(const s of o)e.get(t)?.add(s);else e.set(t,o)},addNsValues=(e,t,o)=>{if(e.has(t))for(const[s,r]of o)addValues(e.get(t),s,r);else e.set(t,o)};